#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include "backprop.h"

#include <cuda.h>
#include <cuda_runtime.h>

#ifdef TIMING
    #include "timing.h"
#endif

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

static int initialize(void)
{
    cudaError_t err;
    int num_devices;

    err = cudaGetDeviceCount(&num_devices);
    if(err != cudaSuccess) { 
        printf("ERROR: cudaGetDeviceCount failed\n"); 
        return -1; 
    }
    printf("num_devices = %d\n", num_devices);

    if(device_id_inuse > num_devices) {
        printf("Invalid Device Number\n");
        return -1;
    }

    err = cudaSetDevice(device_id_inuse);
    if(err != cudaSuccess) { 
        printf("ERROR: cudaSetDevice failed\n"); 
        return -1; 
    }

    return 0;
}

static int shutdown()
{
    cudaDeviceReset();
    return 0;
}

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

unsigned int num_threads = 0;
unsigned int num_blocks = 0;

int
main( int argc, char** argv)
{
	setup(argc, argv);
}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
	int in, hid, out;
	float out_err, hid_err;

	in = net->input_n;
	hid = net->hidden_n;
	out = net->output_n;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif
	if(initialize()) return -1;

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
	float * partial_sum;
	float sum;
	float num_blocks_val = in / BLOCK_SIZE;

	input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	partial_sum = (float *) malloc(num_blocks_val * WIDTH * sizeof(float));


	dim3 global_work(BLOCK_SIZE, BLOCK_SIZE * num_blocks_val, 1);
	dim3 local_work(BLOCK_SIZE, BLOCK_SIZE, 1);



	int m = 0;
	for (int k = 0; k <= in; k++) {
		for (int j = 0; j <= hid; j++) {
		input_weights_one_dim[m] = net->input_weights[k][j];
		input_weights_prev_one_dim[m] = net-> input_prev_weights[k][j];
	    m++;
		}
	}

	float *input_hidden_cuda;
	float *input_cuda;
	float *output_hidden_cuda;
	float *hidden_partial_sum;
	float *hidden_delta_cuda;
	float *input_prev_weights_cuda;

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
	cudaError_t err;
	err = cudaMalloc(&input_cuda, (in + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc input_cuda\n"); return -1;}
	err = cudaMalloc(&input_hidden_cuda, (in + 1) * (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc input_hidden_cuda\n"); return -1;}
	err = cudaMalloc(&output_hidden_cuda, (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc output_hidden_cuda\n"); return -1;}
	err = cudaMalloc(&hidden_partial_sum, num_blocks_val * WIDTH * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc hidden_partial_sum\n"); return -1;}
	err = cudaMalloc(&hidden_delta_cuda, (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc hidden_delta_cuda\n"); return -1;}
	err = cudaMalloc(&input_prev_weights_cuda, (in + 1) * (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc input_prev_weights_cuda\n"); return -1;}
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	printf("Performing GPU computation\n");


	err = cudaMemcpy(input_cuda, net->input_units, (in + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_cuda\n"); return -1; }

	err = cudaMemcpy(input_hidden_cuda, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_hidden_cuda\n"); return -1; }
#ifdef TIMING
    h2d_time += 0.0;
#endif

	bpnn_layerforward_cuda<<<global_work, local_work>>>(input_cuda,
	                                                    output_hidden_cuda,
													    input_hidden_cuda,
													    hidden_partial_sum,
													    in,
													    hid);
	err = cudaDeviceSynchronize();
	if(err != cudaSuccess) { printf("ERROR: bpnn_layerforward_cuda kernel failed\n"); return -1; }
#ifdef TIMING
    kernel_time += 0.0;
#endif

	err = cudaMemcpy(partial_sum, hidden_partial_sum, num_blocks_val * WIDTH * sizeof(float), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy partial_sum\n"); return -1; }
#ifdef TIMING
    d2h_time += 0.0;
#endif

	for (int j = 1; j <= hid; j++) {
		sum = 0.0;
		for (int k = 0; k < num_blocks_val; k++) {
		sum += partial_sum[k * hid + j-1] ;
    }
		sum += net->input_weights[0][j];
		net-> hidden_units[j] = float(1.0 / (1.0 + exp(-sum)));
	}


	bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
	bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
	bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
	bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

	err = cudaMemcpy(hidden_delta_cuda, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy hidden_delta_cuda\n"); return -1; }

	err = cudaMemcpy(input_prev_weights_cuda, input_weights_prev_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_prev_weights_cuda\n"); return -1; }

	err = cudaMemcpy(input_hidden_cuda, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_hidden_cuda\n"); return -1; }
#ifdef TIMING
    h2d_time += 0.0;
#endif

	bpnn_adjust_weights_cuda<<<global_work, local_work>>>(hidden_delta_cuda,
	                                                       hid,
														   input_cuda,
														   in,
														   input_hidden_cuda,
														   input_prev_weights_cuda);
	err = cudaDeviceSynchronize();
	if(err != cudaSuccess) { printf("ERROR: bpnn_adjust_weights_cuda kernel failed\n"); return -1; }
#ifdef TIMING
    kernel_time += 0.0;
#endif

	err = cudaMemcpy(net->input_units, input_cuda, (in + 1) * sizeof(float), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_cuda\n"); return -1; }
#ifdef TIMING
    d2h_time += 0.0;
#endif

	err = cudaMemcpy(input_weights_one_dim, input_hidden_cuda, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_hidden_cuda\n"); return -1; }
#ifdef TIMING
    d2h_time += 0.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	cudaFree(input_cuda);
	cudaFree(output_hidden_cuda);
	cudaFree(input_hidden_cuda);
	cudaFree(hidden_partial_sum);
	cudaFree(input_prev_weights_cuda);

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);

    shutdown();

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

    return 0;
}
